form:Form.form:Scripts:
		var TREE_PATH;

///////////////////////////////////////////////////////////////////////////////          
//EVENTOS     
function RefreshList()
{                 
	var lst;

	if (Ctrl("exportLIST").GetXValue()=="")	lst=new Array();
	                                   else lst=Ctrl("exportLIST").GetXValue().substr(1,Ctrl("exportLIST").GetXValue().length-2).split(";");

	Ctrl("listFILES").IDs=lst;
	Ctrl("listFILES").ResetSQL();

}

function RefreshButtons()
{      
	var aPart=Ctrl("hidTreePATH").GetXValue().split("/");

	CtrlEnabled("contTreePATH_btnSHOW", aPart.length>1);
	CtrlEnabled("contTreePATH_btnEXPORT", aPart.length>1);

	CtrlEnabled("listFILES_DEL", Ctrl("listFILES").GetXValue()!="");
}

function LoadPATHChildren(pobjTree, pobjGroup) 
{
	var retval=new NomadXML("tree");
	var retpath;       

	switch(pobjGroup.FullId)
	{
		case "ORG":  
			retval=GetProxy().SQLService().GetXML(Ctrl("main").getResource("qry:ORG"),"");
			break;

		case "WRK":  
			retval=GetProxy().SQLService().GetXML(Ctrl("main").getResource("qry:WRK"),"");
			break;

		case "INT":  
			retval=GetProxy().SQLService().GetXML(Ctrl("main").getResource("qry:INT"),"");
			break;

		default:                               
			parts=pobjGroup.FullId.split("/");
			switch(parts[0])
			{
				case "ORG":          
					retval=GetProxy().SQLService().GetXML(Ctrl("main").getResource("qry:ORG_CHILD"),'<PARAM oi_organigrama="'+parts[1]+'" />');
					break;

				case "WRK":          
					retval=GetProxy().SQLService().GetXML(Ctrl("main").getResource("qry:WRK_CHILD"),'<PARAM oi_wf="'+parts[1]+'" />');
					break;

				default:
					retpath=retval.AddTailElement("item");
					retpath.SetAttr("id"   , "X");
					retpath.SetAttr("label", "No implementado.");
					break;
			}
			break;
	}

	pobjTree.SetXML(pobjGroup.FullId, retval.ToString());
	return;
}

function OnLoad()
{        
	TREE_PATH = clsClientTree("contTreePATH", "hidTreePATH", "clock3.gif", "folder-close.ico", "folder.ico", "FILE_E.ico", true, LoadPATHChildren, null, RefreshButtons);
	TREE_PATH.SetXML(null, '<tree><group id="WRK" label="Workflows" imgClose="proyecto-grupo_T.ico" imgOpen="proyecto-grupo_T.ico" /><group id="ORG" label="Organigramas" imgClose="proyecto-grupo_I.ico" imgOpen="proyecto-grupo_I.ico" /><group id="INT" label="Interfaces" imgClose="tarea_T.ico" imgOpen="tarea_T.ico" /></tree>');

	RefreshButtons();
}

function ShowItem()
{
	var aPart=Ctrl("hidTreePATH").GetXValue().split("/");
	switch(aPart[0])
	{
		case "ORG":               
			appendFormInMain("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.flow", "SHOW", '<DATA PARENT="'+aPart[aPart.length-1]+'" />');		
			break;

		case "WRK":
			appendFormInMain("NucleusWF.Base.Definicion.Workflows.PROCESS.flow", "LIST", '<DATA PARENT="'+aPart[aPart.length-1]+'" />');		          
			break;

		case "INT":          
			appendFormInMain("NucleusWF.Base.Definicion.Integracion.INT_MAG.MAIN.STD.autoflow", "SHOW", '<DATA ID="'+aPart[aPart.length-1]+'" />');		
			break;
	}
}

function ExportItem()
{
	var aPart=Ctrl("hidTreePATH").GetXValue().split("/");
	var OBJ_ID;

	switch(aPart[0])
	{
		case "ORG":               
			OBJ_ID="ORG:"+aPart[aPart.length-1];
			break;

		case "WRK":
			OBJ_ID="WRK:"+aPart[aPart.length-1];
			break;

		case "INT":
			OBJ_ID="INT:"+aPart[aPart.length-1];          
			break;
	}


	//Lo agrego a la Lista a Exportar
	if (Ctrl("exportLIST").GetXValue().indexOf(";"+OBJ_ID+";")<0)
	{                         
		if (Ctrl("exportLIST").GetXValue()=="") Ctrl("exportLIST").SetXValue(";"+OBJ_ID+";");
		                                   else Ctrl("exportLIST").SetXValue(Ctrl("exportLIST").GetXValue()+OBJ_ID+";");

		RefreshList();
	} else
	{
		alert("El elemento seleccionado ya esta en la lista");
	}
}

function DeleteItem()
{
	//Hay algo selecionado? 
	if (Ctrl("listFILES").GetXValue() == "") return;

	//Lista de Valores
	var expList=Ctrl("exportLIST").GetXValue();

	//Existe el ITEM?
	if (expList.indexOf(";"+Ctrl("listFILES").GetXValue()+";")<0) return;

	//Elimino el ITEM
	expList=Replace(expList,";"+Ctrl("listFILES").GetXValue()+";",";");
	if (expList==";") expList="";

	//Actualizo la LISTA
	Ctrl("exportLIST").SetXValue(expList);
	Ctrl("listFILES").SetXValue("");
	RefreshList();
	RefreshButtons();
}
